text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "id": "D1",
        "decision": "공개 릴리스 목표 시각은 스모크 테스트 통과를 전제로 금요일 15:00 KST로 한다."
      },
      {
        "id": "D2",
        "decision": "packageName 불일치 발생 시 먼저 패키지 설정(계약)을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토로 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "id": "R1",
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "proposed_by": "Hara",
        "result": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "id": "S1",
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표이며 최종 공개 릴리스 확정안이 아님"
      }
    ],
    "non_decisions": [
      {
        "id": "N1",
        "item": "README 설치 단계 검토 필요성은 제기되었으나 담당자 미지정"
      },
      {
        "id": "N2",
        "item": "Hara의 tarball 경로 점검은 Minjun 결과 공유 이후로만 합의되었고 정확한 마감 시각은 미설정"
      }
    ],
    "risks": [
      {
        "id": "K1",
        "risk": "tarball 경로 오류 시 릴리스 지연 가능"
      },
      {
        "id": "K2",
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "id": "Q1",
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "id": "Q2",
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "정확한 마감 시각 미설정",
      "status": "대기",
      "source_certainty": "확정(시점 조건부)"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면)",
      "status": "담당자 미배정",
      "source_certainty": "제안(비확정)"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 기준 Minjun 스모크 테스트 결과 수신 여부",
      "금요일 12:00 KST 기준 Doyun 트리아지 노트 작성 완료 여부",
      "Minjun 결과 공유 직후 Hara의 tarball 경로 점검 결과",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 결정"
    ],
    "what_not_to_invent": [
      "고객/외부 파트너 정보",
      "예산 정보",
      "보안 사고 사실",
      "프로덕션 장애 사실",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감 시각"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객명, 예산, 보안, 장애, 법무 관련 사실을 추가하지 않는다.",
    "미확정 항목은 확정으로 승격하지 않는다.",
    "담당자 미지정 항목에 임의 소유자를 부여하지 않는다.",
    "정확한 시각이 없는 항목에 임의 마감 시각을 추가하지 않는다.",
    "기각된 제안을 최종 결정처럼 기록하지 않는다.",
    "내부 스트레치 목표와 확정 공개 목표를 혼동하지 않는다."
  ]
}
